sql:
SELECT AVG(std_pack) AS average_std_pack
FROM inventory
WHERE bin_id = 'your_bin_id';

SELECT customer_id, SUM(order_total) AS total_shipping_cost
FROM purchase_orders
GROUP BY customer_id;

SELECT COUNT(*) as total_shipments
FROM shipping
WHERE shipping_method = 'ground' AND shipping_carrier = 'FedEx';

SELECT product_name
FROM products
WHERE product_id NOT IN (
  SELECT product_id 
  FROM inventory
);

SELECT SUM(total_qty) AS total_quantity
FROM inventory
WHERE product_id = 'SPECIFIC_PRODUCT_ID';

SELECT po_id, ship_to
FROM purchase_orders
WHERE order_total > (SELECT AVG(order_total) FROM purchase_orders);

SELECT p.product_name
FROM products p
INNER JOIN inventory i ON p.product_id = i.product_id;

SELECT SUM(po.order_total) AS total_order_value
FROM purchase_orders po
JOIN shipping sh ON po.po_id = sh.po_id;

SELECT order_total AS Total_Cost
FROM purchase_orders
WHERE po_id = 'your_desired_purchase_order_id';
